def solve_tsp(points, p=None):
    if p is None:
        p = {"angle_threshold": 0.5}  # Threshold for angle sorting

    n = len(points)
    if n <= 1:
        return list(range(n))

    cx = sum(x for x, y in points) / n
    cy = sum(y for x, y in points) / n

    def angle(point):
        dx = point[0] - cx
        dy = point[1] - cy
        if dx == 0:
            return float('inf') if dy >= 0 else -float('inf')
        return math.atan2(dy, dx)

    sorted_points = sorted(range(n), key=lambda i: angle(points[i]))

    tour = [sorted_points[0]]
    for i in range(1, n):
        last = tour[-1]
        next_point = (last + 1) % n
        if abs(angle(points[next_point]) - angle(points[last])) < p["angle_threshold"]:
            tour.append(next_point)
        else:
            tour.append(sorted_points[i])

    return tour
