def solve_tsp(points, p=None):
    if p is None:
        p = {"alpha": 1.0, "lookahead_weight": 1.0}

    n = len(points)
    if n <= 1:
        return list(range(n))

    # Precompute the distance matrix
    dist = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            dx = points[i][0] - points[j][0]
            dy = points[i][1] - points[j][1]
            dist[i][j] = dist[j][i] = (dx * dx + dy * dy) ** 0.5

    # Multi-start nearest-neighbor heuristic
    best_tour = None
    best_dist = float('inf')
    for start in range(n):
        visited = [False] * n
        tour = [start]
        visited[start] = True
        for _ in range(n - 1):
            last = tour[-1]
            best_next = min(range(n), key=lambda j: dist[last][j] if not visited[j] else float('inf'))
            tour.append(best_next)
            visited[best_next] = True
        # Calculate the total distance of the current tour
        current_dist = sum(dist[tour[i]][tour[(i + 1) % n]] for i in range(n))
        if current_dist < best_dist:
            best_tour = tour[:]
            best_dist = current_dist

    # Local search to improve the initial tour using 2-opt algorithm
    improved = True
    while improved:
        improved = False
        for i in range(1, n - 2):
            for j in range(i + 2, n):
                if j == n - 1:
                    continue
                original_dist = dist[best_tour[i-1]][best_tour[i]] + dist[best_tour[j]][best_tour[j+1]]
