        dy = points[i][1] - points[j][1]
        return (dx * dx + dy * dy) ** 0.5

    def tour_length(tour):
        return sum(dist(tour[i], tour[(i + 1) % len(tour)]) for i in range(len(tour)))

    def two_opt(tour):
        improved = True
        while improved:
            improved = False
            for i in range(len(tour) - 1):
                for j in range(i + 2, len(tour)):
                    a, b = tour[i], tour[i + 1]
                    c, d = tour[j], tour[(j + 1) % len(tour)]
                    if dist(a, b) + dist(c, d) > dist(a, c) + dist(b, d):
                        tour[i + 1:j + 1] = tour[i + 1:j + 1][::-1]
                        improved = True
                        break
                if improved:
                    break
        return tour

    def or_opt(tour, seg_len):
        # Relocate non-overlapping segments of length seg_len
        best = tour[:]
        best_len = tour_length(tour)
        for i in range(len(tour) - seg_len + 1):
            segment = tour[i:i + seg_len]
            remaining = tour[:i] + tour[i + seg_len:]
            for j in range(len(remaining) + 1):
                candidate = remaining[:j] + segment + remaining[j:]
                cand_len = tour_length(candidate)
                if cand_len < best_len:
                    best = candidate
                    best_len = cand_len
        return best

    best_tour = None
    best_len = float('inf')

