```python
def solve(items, capacity, p=None):
    if p is None:
        p = {"convergence_threshold": 0.001, "max_iterations": 1000}

    # Initial greedy solution
    indexed = [(v / max(w, 1), w, v, i) for i, (w, v) in enumerate(items)]
    indexed.sort(reverse=True)

    total_w, total_v = 0, 0
    selected = []
    for ratio, w, v, i in indexed:
        if total_w + w <= capacity:
            total_w += w
            total_v += v
            selected.append(i)

    best_value = total_v

    # Hill climbing with convergence detection
    for iteration in range(p["max_iterations"]):
        improved = False

        # Try single-item swaps to improve solution
        for i_sel in range(len(selected)):
            idx_sel = selected[i_sel]
            w_sel, v_sel = items[idx_sel]
            freed_capacity = total_w - w_sel

            for idx_unsel in range(len(items)):
                if idx_unsel not in selected:
                    w_unsel, v_unsel = items[idx_unsel]
                    if w_unsel <= capacity - freed_capacity:
                        new_value = total_v - v_sel + v_unsel
                        if new_value - best_value > p["convergence_threshold"]:
                            selected[i_sel] = idx_unsel
                            total_w = freed_capacity + w_unsel
                            total_v = new_value
                            best_value = new_value
                            improved = True
                            break

            if improved:
                break

        if not improved:
            break

    return (best_value, selected)
```

