```python
def solve(items, capacity, p=None):
    if p is None:
        p = {}
    n = len(items)
    memo = {}

    def dp(i, c):
        # Returns max value using items[i:] with capacity c
        if i == n or c == 0:
            return 0
        if (i, c) in memo:
            return memo[(i, c)]

        w, v = items[i]
        # Skip this item or take it (if it fits)
        skip = dp(i + 1, c)
        take = v + dp(i + 1, c - w) if w <= c else 0

        result = max(skip, take)
        memo[(i, c)] = result
        return result

    total_value = dp(0, capacity)

    # Reconstruct selected items by tracing back through decisions
    selected = []
    def reconstruct(i, c):
        if i == n or c == 0:
            return
        w, v = items[i]
        # Check if taking this item was part of the optimal solution
        if w <= c and v + memo.get((i + 1, c - w), 0) >= memo.get((i + 1, c), 0):
            selected.append(i)
            reconstruct(i + 1, c - w)
        else:
            reconstruct(i + 1, c)

    reconstruct(0, capacity)
    return (total_value, selected)
```

