```python
def solve(items, capacity, p=None):
    if p is None:
        p = {"use_dp": 1}
    n = len(items)
    if n == 0:
        return (0, [])
    max_w = max(w for w, v in items)
    INF = float('-inf')
    # Pad columns [0, max_w-1] with sentinels so c - w is always in bounds
    # Columns [max_w, max_w+capacity] are actual DP values
    cols = max_w + capacity + 1
    dp = [[INF] * cols for _ in range(n + 1)]
    # Base case: capacity 0 (column max_w) has value 0
    for i in range(n + 1):
        dp[i][max_w] = 0

    for i in range(1, n + 1):
        w, v = items[i - 1]
        for c in range(max_w, cols):
            # Don't take item i
            dp[i][c] = dp[i-1][c]
            # Take item i: no bounds check needed, sentinel columns handle out-of-bounds safely
            dp[i][c] = max(dp[i][c], dp[i-1][c - w] + v)

    selected = []
    c = capacity + max_w
    for i in range(n, 0, -1):
        if dp[i][c] != dp[i-1][c]:
            selected.append(i - 1)
            c -= items[i-1][0]
    return (dp[n][capacity + max_w], selected[::-1])
