```python
def solve(f, a, b, p=None):
    if p is None:
        p = {"tolerance": 1e-6, "max_depth": 20}

    def simpson_quad(f, a, b):
        # Single Simpson's rule application
        c = (a + b) / 2
        h = (b - a) / 6
        return h * (f(a) + 4*f(c) + f(b))

    def adaptive_simpson(f, a, b, tol, depth):
        # Adaptive refinement via recursion
        if depth <= 0:
            return simpson_quad(f, a, b)

        c = (a + b) / 2
        whole = simpson_quad(f, a, b)
        left = simpson_quad(f, a, c)
        right = simpson_quad(f, c, b)

        if abs(left + right - whole) <= 15 * tol:
            return left + right + (left + right - whole) / 15

        return adaptive_simpson(f, a, c, tol/2, depth-1) + adaptive_simpson(f, c, b, tol/2, depth-1)

    return adaptive_simpson(f, a, b, p["tolerance"], p["max_depth"])
