def solve(f, a, b, p=None):
    if p is None:
        p = {"tolerance": 1e-5, "max_depth": 50}

    cache = {}

    def get_f(x):
        # Memoize function evaluations to avoid redundant calls
        if x not in cache:
            cache[x] = f(x)
        return cache[x]

    def simpson(a, b):
        # Simpson's rule: more accurate than trapezoidal
        m = (a + b) / 2
        h = (b - a) / 6
        return h * (get_f(a) + 4*get_f(m) + get_f(b))

    def adaptive(a, b, tol, whole, depth):
        # Recursively subdivide intervals where error is too large
        if depth >= p["max_depth"]:
            return whole
        c = (a + b) / 2
        left = simpson(a, c)
        right = simpson(c, b)

        # Richardson extrapolation error estimate
        if abs(left + right - whole) <= 15 * tol:
            return left + right + (left + right - whole) / 15
        else:
            return adaptive(a, c, tol/2, left, depth+1) + adaptive(c, b, tol/2, right, depth+1)

    return adaptive(a, b, p["tolerance"], simpson(a, b), 0)
